const rows = $input.all();
const cfg = {};
for (const item of rows) {
  cfg[item.json.Name] = item.json.Value;
}

const requiredKeys = ['OpenAI_ApiKey'];

for (const key of requiredKeys) {
  if (!cfg[key]) {
    throw new Error('[Build Config] Missing required key: ' + key + '. Add it to EnvironmentVariables table.');
  }
}

return [{ json: cfg }];

const openaiResponse = items[0].json;
const sourceData = $('Code: Build QA Prompt').first().json;

const originalInput = {
  idea_id: sourceData.idea_id,
  idea_title: sourceData.idea_title,
  script: sourceData.script,
  retry_count: sourceData.retry_count || 0,
  prompt_version: sourceData.prompt_version,
  content_strategy_version: sourceData.content_strategy_version
};

let qaResult;
try {
  const responseContent = openaiResponse.choices[0].message.content;
  qaResult = JSON.parse(responseContent);
} catch (e) {
  return [{
    json: {
      ...originalInput,
      scores: {
        hook_strength: 0, interaction_quality: 0, naturalness: 0,
        standalone_clarity: 0, engagement_payoff: 0,
        moment_clarity: 0, escalation_strength: 0, persona_distinction: 0,
        relatability: 0, safety_brand_fit: 0
      },
      hook_strength: 0,
      interaction_quality: 0,
      naturalness: 0,
      standalone_clarity: 0,
      engagement_payoff: 0,
      weighted_score: 0,
      hard_fail: true,
      hard_fail_reasons: ['LLM_PARSE_ERROR: ' + e.message],
      main_issues: ['Failed to parse QA evaluator response'],
      fix_instructions: ['Re-run QA evaluation'],
      qa_decision: 'REJECTED',
      qa_timestamp: new Date().toISOString()
    }
  }];
}

const scores = qaResult.scores;

const weighted_score = parseFloat((
  0.16 * (scores.hook_strength || 0) +
  0.14 * (scores.interaction_quality || 0) +
  0.14 * (scores.engagement_payoff || 0) +
  0.14 * (scores.escalation_strength || 0) +
  0.12 * (scores.moment_clarity || 0) +
  0.10 * (scores.naturalness || 0) +
  0.08 * (scores.standalone_clarity || 0) +
  0.08 * (scores.persona_distinction || 0) +
  0.02 * (scores.relatability || 0) +
  0.02 * (scores.safety_brand_fit || 0)
).toFixed(2));

const hardFailReasons = Array.isArray(qaResult.hard_fail_reasons) ? [...qaResult.hard_fail_reasons] : [];

if (scores.hook_strength < 7)
  hardFailReasons.push('hook_strength ' + scores.hook_strength + ' below threshold 7');
if (scores.interaction_quality < 7)
  hardFailReasons.push('interaction_quality ' + scores.interaction_quality + ' below threshold 7');
if (scores.escalation_strength < 7)
  hardFailReasons.push('escalation_strength ' + scores.escalation_strength + ' below threshold 7');
if (scores.engagement_payoff < 6)
  hardFailReasons.push('engagement_payoff ' + scores.engagement_payoff + ' below threshold 6');
if (scores.safety_brand_fit < 9)
  hardFailReasons.push('safety_brand_fit ' + scores.safety_brand_fit + ' below threshold 9');

const hard_fail = hardFailReasons.length > 0;

let qa_decision;
if (hard_fail) {
  qa_decision = 'REJECTED';
} else if (
  weighted_score >= 8.2 &&
  scores.hook_strength >= 8 &&
  scores.escalation_strength >= 8 &&
  scores.interaction_quality >= 8
) {
  qa_decision = 'APPROVED';
} else if (weighted_score >= 6.8) {
  qa_decision = 'RETRY';
} else {
  qa_decision = 'REJECTED';
}

return [{
  json: {
    ...originalInput,
    scores,
    hook_strength: scores.hook_strength || 0,
    interaction_quality: scores.interaction_quality || 0,
    naturalness: scores.naturalness || 0,
    standalone_clarity: scores.standalone_clarity || 0,
    engagement_payoff: scores.engagement_payoff || 0,
    weighted_score,
    hard_fail,
    hard_fail_reasons: hardFailReasons,
    main_issues: qaResult.main_issues || [],
    fix_instructions: qaResult.fix_instructions || [],
    qa_decision,
    qa_timestamp: new Date().toISOString()
  }
}];

const input = items[0].json;
return [{
  json: {
    status: 'APPROVED',
    pipeline_stage: 'voiceover',
    idea_id: input.idea_id,
    idea_title: input.idea_title,
    script: input.script,
    retry_count: input.retry_count,
    prompt_version: input.prompt_version,
    content_strategy_version: input.content_strategy_version,
    qa_result: {
      weighted_score: input.weighted_score,
      hook_strength: input.hook_strength,
      interaction_quality: input.interaction_quality,
      naturalness: input.naturalness,
      standalone_clarity: input.standalone_clarity,
      engagement_payoff: input.engagement_payoff,
      scores: input.scores,
      decision: 'APPROVED',
      qa_timestamp: input.qa_timestamp
    }
  }
}];

const input = items[0].json;
return [{
  json: {
    ...input,
    retry_count: (input.retry_count || 0) + 1
  }
}];

const input = items[0].json;
const rejection_type = (input.retry_count || 0) >= 2 ? 'MAX_RETRIES_EXCEEDED' : 'LOW_SCORE';
return [{
  json: {
    status: 'REJECTED',
    rejection_type,
    pipeline_stage: 'archive',
    idea_id: input.idea_id,
    idea_title: input.idea_title,
    retry_count: input.retry_count,
    prompt_version: input.prompt_version,
    content_strategy_version: input.content_strategy_version,
    qa_result: {
      weighted_score: input.weighted_score,
      hook_strength: input.hook_strength,
      interaction_quality: input.interaction_quality,
      naturalness: input.naturalness,
      standalone_clarity: input.standalone_clarity,
      engagement_payoff: input.engagement_payoff,
      scores: input.scores,
      hard_fail_reasons: input.hard_fail_reasons || [],
      main_issues: input.main_issues,
      fix_instructions: input.fix_instructions,
      decision: 'REJECTED',
      qa_timestamp: input.qa_timestamp
    }
  }
}];
